// === Construir prompt para el LLM ===
const body = $input.item.json.body;

const systemPrompt = `Eres un psicólogo cognitivo especializado en atención y productividad académica.
Analizas datos de comportamiento de estudiantes universitarios y generas
informes claros, empáticos y accionables. Tu audiencia son jóvenes de 18-25 años.
Escribe en español. Sé directo, usa lenguaje cercano (no clínico), y basa
tus conclusiones únicamente en los datos recibidos. No inventes métricas.
Si una métrica es null, no la menciones ni la asumas.
Responde ÚNICAMENTE con un objeto JSON válido, sin markdown, sin texto extra.`;

// Construir sección de métricas de atención (solo las que no son null)
const attentionLines = [];
const am = body.attention_metrics || {};
if (am.avg_reaction_time_ms != null) {
  attentionLines.push(`- Tiempo de reacción promedio: ${am.avg_reaction_time_ms}ms`);
}
if (am.sustained_attention_score != null) {
  attentionLines.push(`- Atención sostenida (accuracy): ${am.sustained_attention_score}%`);
}
if (am.working_memory_span != null) {
  attentionLines.push(`- Memoria de trabajo (span): ${am.working_memory_span} ítems`);
}
if (am.focus_consistency != null) {
  attentionLines.push(`- Consistencia de enfoque: ${(am.focus_consistency * 100).toFixed(1)}%`);
}

// Construir sección de productividad
const pm = body.productivity_metrics || {};
const productivityLines = [];
productivityLines.push(`- Pomodoros completados: ${pm.pomodoros_completed}`);
productivityLines.push(`- Pomodoros interrumpidos: ${pm.pomodoros_interrupted}`);
productivityLines.push(`- Tasa de completación: ${(pm.completion_rate * 100).toFixed(1)}%`);
if (pm.avg_focus_rating != null) {
  productivityLines.push(`- Rating de enfoque promedio: ${pm.avg_focus_rating}/5`);
}
productivityLines.push(`- Tareas completadas: ${pm.tasks_completed}`);
productivityLines.push(`- Tareas vencidas: ${pm.tasks_overdue}`);
productivityLines.push(`- Consistencia de hábitos: ${(pm.habit_consistency * 100).toFixed(1)}%`);

// Historial de actividades
const history = body.activity_history || [];
const activityText = history.length > 0
  ? history.map(a => `- ${a.activity}: score ${a.score}/${a.max_score}`).join('\n')
  : '- Ninguna en este período';

const up = body.user_profile || {};
const s = body.summary || {};
const p = body.patterns || {};

const userMessage = `Analiza el siguiente perfil de atención y productividad del estudiante:

PERFIL:
- Universidad: ${up.university || 'No especificada'}
- Carrera: ${up.career || 'No especificada'}
- Semestre: ${up.semester || 'No especificado'}

PERÍODO ANALIZADO: ${body.period.start} a ${body.period.end}

RESUMEN DE ACTIVIDAD:
- Días activos: ${s.active_days}
- Sesiones totales: ${s.total_sessions}
- Tiempo total de enfoque: ${s.total_focus_time_minutes} minutos
- Duración promedio de sesión: ${s.avg_session_duration_minutes} minutos

MÉTRICAS DE ATENCIÓN:
${attentionLines.join('\n')}

PRODUCTIVIDAD:
${productivityLines.join('\n')}

PATRONES HORARIOS:
- Horas pico de actividad: ${(p.peak_focus_hours || []).join(', ')}h
- Horas de baja actividad: ${(p.low_focus_hours || []).join(', ')}h

ACTIVIDADES REALIZADAS:
${activityText}

Genera un análisis completo. Devuelve ÚNICAMENTE un objeto JSON válido con esta estructura (sin markdown, sin texto extra antes o después):

{
  "attention_profile": "string — nombre del perfil atencional (ej: 'Focused Sprinter', 'Deep Diver', 'Scattered Thinker', 'Steady Builder', 'Night Owl Learner')",
  "summary": "string — párrafo de 3-4 oraciones describiendo el patrón general del estudiante",
  "strengths": ["string", "string", "string"],
  "areas_to_improve": ["string", "string", "string"],
  "patterns_detected": ["string", "string", "string"],
  "recommendations": ["string", "string", "string", "string"],
  "risk_indicators": {
    "burnout_risk": "low | moderate | high",
    "attention_deficit_indicators": "none | mild | moderate | significant",
    "stress_patterns": "string — descripción breve del patrón de estrés detectado"
  }
}`;

return [{
  json: {
    system_prompt: systemPrompt,
    user_message: userMessage,
    report_id: body.report_id
  }
}];

// === Parsear respuesta de OpenAI ===
const response = $input.item.json;

// Verificar si hubo error en la llamada HTTP
if (response.error) {
  throw new Error(`OpenAI API error: ${JSON.stringify(response.error)}`);
}

const text = response.choices[0].message.content.trim();

let analysis;
try {
  const clean = text.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').trim();
  analysis = JSON.parse(clean);
} catch (e) {
  throw new Error('El LLM no devolvió JSON válido: ' + text.substring(0, 200));
}

// Validar estructura mínima
const requiredKeys = ['attention_profile', 'summary', 'strengths', 'areas_to_improve', 'recommendations', 'risk_indicators'];
const missing = requiredKeys.filter(k => !(k in analysis));
if (missing.length > 0) {
  throw new Error(`Respuesta incompleta, faltan campos: ${missing.join(', ')}`);
}

return [{
  json: {
    analysis,
    report_id: $('Construir Prompt').item.json.report_id
  }
}];
